                {"swissGerman": "aa z'mache", "german": "anzumachen", "explanation": "'aa z'mache' = 'anzumachen'. Separable prefix."},
                {"swissGerman": "Huusmeischter", "german": "Hausmeister", "explanation": "'Huus-' = 'Haus-', 'meischter' = 'meister'."},
                {"swissGerman": "verbii", "german": "vorbei", "explanation": "'verbii' = 'vorbei'. Vowel shifts."},
