                {"swissGerman": "chunnt druf aa", "german": "kommt darauf an", "explanation": "'chunnt' = 'kommt', 'druf' = 'darauf', 'aa' = 'an'."},
                {"swissGerman": "Uuszug", "german": "Auszug", "explanation": "'Uuszug' = 'Auszug'. 'Aus' → 'Uus'."},
